#include <stdio.h>
#include <stdlib.h>

int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int* A = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        // Calculate distances and find minimum sum of road lengths
        int* distances = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            distances[i] = 0;
            for (int j = 0; j < N; j++) {
                if (i != j) {
                    distances[i] += A[j];
                }
            }
        }
        int min_sum = 0;
        for (int i = 0; i < N; i++) {
            min_sum += distances[i];
        }
        printf("YES\n");
        for (int i = 0; i < N; i++) {
            printf("%d ", distances[i]);
        }
        printf("\n");
        free(A);
        free(distances);
    }
    return 0;
}

